        if (userInfo == null) {
            throw new ServiceException("用户不存在");
        }

        // 校验密码
        if (!userInfo.getPassword().equals(reqDTO.getPassword())) {
            throw new ServiceException("密码错误");
        }

        // 登录成功，返回用户信息
        return BeanUtils.copyProperties(userInfo, AdminUserLoginRespDTO.class);
    }
}
```

